-- Словарь звукорежиссёра переезжает из статического массива в JS в базу:
-- категории + термины, с богатым (HTML) описанием у каждого термина —
-- тот же редактор, что и в курсах, так что в описание можно вставлять
-- картинки, ссылки, таблицы (например, для примеров "до / после").
-- Выполнить после всех предыдущих миграций.

create table if not exists glossary_categories (
  id uuid primary key default gen_random_uuid(),
  title text not null,
  order_index integer not null default 0,
  created_at timestamptz not null default now()
);

create table if not exists glossary_terms (
  id uuid primary key default gen_random_uuid(),
  category_id uuid references glossary_categories(id) on delete set null,
  term text not null,
  definition text not null default '',
  order_index integer not null default 0,
  created_at timestamptz not null default now()
);
create index if not exists idx_glossary_terms_cat on glossary_terms(category_id, order_index);

alter table glossary_categories enable row level security;
drop policy if exists glossary_categories_select_all on glossary_categories;
create policy glossary_categories_select_all on glossary_categories for select using (true);
drop policy if exists glossary_categories_write_staff on glossary_categories;
create policy glossary_categories_write_staff on glossary_categories for all
  using (exists (select 1 from profiles p where p.id = auth.uid() and p.role in ('VERIFIED_PRO','MENTOR','ADMIN')))
  with check (exists (select 1 from profiles p where p.id = auth.uid() and p.role in ('VERIFIED_PRO','MENTOR','ADMIN')));

alter table glossary_terms enable row level security;
drop policy if exists glossary_terms_select_all on glossary_terms;
create policy glossary_terms_select_all on glossary_terms for select using (true);
drop policy if exists glossary_terms_write_staff on glossary_terms;
create policy glossary_terms_write_staff on glossary_terms for all
  using (exists (select 1 from profiles p where p.id = auth.uid() and p.role in ('VERIFIED_PRO','MENTOR','ADMIN')))
  with check (exists (select 1 from profiles p where p.id = auth.uid() and p.role in ('VERIFIED_PRO','MENTOR','ADMIN')));

-- ── Категории (фиксированные id, чтобы термины ниже могли на них ссылаться) ──
insert into glossary_categories (id, title, order_index) values
  ('00000000-0000-0000-0000-000000000001', 'Эквализация', 1),
  ('00000000-0000-0000-0000-000000000002', 'Динамика и компрессия', 2),
  ('00000000-0000-0000-0000-000000000003', 'Громкость и метрика', 3),
  ('00000000-0000-0000-0000-000000000004', 'Пространство и стерео', 4),
  ('00000000-0000-0000-0000-000000000005', 'Запись', 5),
  ('00000000-0000-0000-0000-000000000006', 'Сведение', 6),
  ('00000000-0000-0000-0000-000000000007', 'Мастеринг', 7),
  ('00000000-0000-0000-0000-000000000008', 'Модуляция и эффекты', 8),
  ('00000000-0000-0000-0000-000000000009', 'Синтез и электронная музыка', 9),
  ('00000000-0000-0000-0000-000000000010', 'Форматы и технологии', 10)
on conflict (id) do nothing;

-- ── Термины ──
insert into glossary_terms (category_id, term, definition, order_index) values
-- Эквализация
('00000000-0000-0000-0000-000000000001','Q-фактор','<p>Ширина полосы EQ-фильтра вокруг центральной частоты. Узкий Q — точечная правка (убрать резонанс), широкий Q — мягкая тональная коррекция.</p>',1),
('00000000-0000-0000-0000-000000000001','Полочный фильтр (Shelf)','<p>Поднимает или срезает всё выше/ниже заданной частоты плоской «полкой», а не колоколом. Хорош для общей тональной балансировки.</p>',2),
('00000000-0000-0000-0000-000000000001','Колокольный фильтр (Bell)','<p>Поднимает или срезает узкий диапазон вокруг центральной частоты — самый частый тип EQ-фильтра, «горб» или «яма» на графике.</p>',3),
('00000000-0000-0000-0000-000000000001','High-pass / Low-pass фильтр','<p>High-pass срезает всё ниже заданной частоты (убирает гул), Low-pass — всё выше (убирает шипение и лишний воздух).</p>',4),
('00000000-0000-0000-0000-000000000001','Резонанс','<p>Нежелательный подъём на узкой частоте — из-за помещения, инструмента или самого фильтра. Обычно вырезается узким колоколом на слух.</p>',5),
('00000000-0000-0000-0000-000000000001','Сибилянты','<p>Резкие свистящие звуки речи и вокала («с», «ш», «ц») в районе 5–9 кГц. Убираются де-эссером или точечным вырезом EQ.</p>',6),
('00000000-0000-0000-0000-000000000001','Динамический EQ','<p>Эквалайзер, у которого сила действия конкретной полосы зависит от уровня сигнала — работает как гибрид EQ и компрессора: например, режет резонанс только когда он становится громким.</p>',7),
('00000000-0000-0000-0000-000000000001','Notch-фильтр','<p>Очень узкий и глубокий вырез на конкретной частоте — используется, чтобы почти полностью убрать свист, гул сети (50/60 Гц) или паразитный тон.</p>',8),
('00000000-0000-0000-0000-000000000001','M/S-эквализация','<p>Раздельная обработка EQ для Mid (общий, моно) и Side (стерео-разница) каналов — например, можно почистить низкие частоты только в Side, не трогая моно-центр.</p>',9),
('00000000-0000-0000-0000-000000000001','Кривые Флетчера — Мансона','<p>Кривые равной громкости, показывающие, что человеческое ухо неодинаково чувствительно к разным частотам на разной громкости — низкие и высокие частоты субъективно «пропадают» на тихой громкости прослушивания.</p>',10),

-- Динамика и компрессия
('00000000-0000-0000-0000-000000000002','Attack (атака)','<p>Как быстро компрессор или лимитер начинает сжимать сигнал после того, как он превысил порог (threshold).</p>',1),
('00000000-0000-0000-0000-000000000002','Release (восстановление)','<p>Как быстро компрессор перестаёт сжимать сигнал после того, как он опустился ниже порога.</p>',2),
('00000000-0000-0000-0000-000000000002','Ratio (степень сжатия)','<p>Во сколько раз уменьшается превышение порога. При 4:1 превышение на 4 дБ на выходе станет превышением всего на 1 дБ.</p>',3),
('00000000-0000-0000-0000-000000000002','Threshold (порог)','<p>Уровень громкости, начиная с которого компрессор, лимитер или гейт начинают работать.</p>',4),
('00000000-0000-0000-0000-000000000002','Knee (колено)','<p>Мягкий (soft knee) или резкий (hard knee) переход компрессора в режим сжатия возле порога — влияет на то, насколько «незаметно» работает компрессия.</p>',5),
('00000000-0000-0000-0000-000000000002','Sidechain','<p>Компрессор реагирует не на сам сигнал, а на другой — например, бас автоматически «подкачивается» под удар кика, освобождая ему место.</p>',6),
('00000000-0000-0000-0000-000000000002','Лимитер','<p>Компрессор с очень высоким ratio (обычно ∞:1) — не даёт сигналу превысить заданный потолок громкости.</p>',7),
('00000000-0000-0000-0000-000000000002','Гейт (Noise Gate)','<p>Заглушает сигнал ниже порога — убирает шум между фразами вокала или наводки на дорожке в паузах.</p>',8),
('00000000-0000-0000-0000-000000000002','Экспандер','<p>Мягкая версия гейта: не полностью заглушает сигнал ниже порога, а плавно уменьшает его громкость, сохраняя динамику тише порога.</p>',9),
('00000000-0000-0000-0000-000000000002','Многополосная компрессия','<p>Сигнал делится на несколько частотных полос, и каждая сжимается своим отдельным компрессором — позволяет, например, утихомирить только бас, не трогая середину и верх.</p>',10),
('00000000-0000-0000-0000-000000000002','Параллельная компрессия','<p>Сильно сжатая копия сигнала подмешивается к оригиналу («нью-йоркская компрессия») — даёт плотность и громкость, сохраняя естественную динамику оригинала.</p>',11),
('00000000-0000-0000-0000-000000000002','Look-ahead','<p>Компрессор или лимитер «заранее» анализирует сигнал на несколько миллисекунд вперёд, чтобы среагировать до пика, а не с запозданием — снижает искажения на быстрых транзиентах.</p>',12),
('00000000-0000-0000-0000-000000000002','Транзиент-шейпер','<p>Отдельно усиливает или ослабляет атаку (transient) и «хвост» (sustain) звука — например, добавляет щелчку кика больше удара без изменения громкости всей ноты.</p>',13),
('00000000-0000-0000-0000-000000000002','De-esser','<p>Специализированный компрессор, который сжимает сигнал только в узкой полосе сибилянтов (5–9 кГц), не трогая остальной вокал.</p>',14),
('00000000-0000-0000-0000-000000000002','Peak vs RMS детектор','<p>То, как компрессор «слышит» громкость: по мгновенным пикам (Peak, реагирует резко) или по усреднённой энергии сигнала (RMS, реагирует мягче и музыкальнее).</p>',15),

-- Громкость и метрика
('00000000-0000-0000-0000-000000000003','LUFS','<p>Единица измерения воспринимаемой громкости всего трека (в отличие от пиковой). Стриминги нормализуют треки именно по LUFS, не по пикам.</p>',1),
('00000000-0000-0000-0000-000000000003','dBFS','<p>Единица измерения уровня сигнала относительно цифрового максимума. 0 dBFS — потолок, выше только клиппинг.</p>',2),
('00000000-0000-0000-0000-000000000003','True Peak','<p>Реальный пик сигнала после цифро-аналогового преобразования — может быть выше, чем показывает обычный измеритель (Inter-Sample Peak).</p>',3),
('00000000-0000-0000-0000-000000000003','Динамический диапазон','<p>Разница между самым тихим и самым громким местом трека. «Зажатый» перекомпрессированный трек имеет маленький диапазон.</p>',4),
('00000000-0000-0000-0000-000000000003','Война громкости (Loudness War)','<p>Гонка за максимально громким мастерингом в ущерб динамике трека. Нормализация громкости в стримингах во многом обесценила эту гонку.</p>',5),
('00000000-0000-0000-0000-000000000003','Headroom (запас)','<p>Расстояние в дБ между текущим пиковым уровнем сигнала и цифровым потолком 0 dBFS.</p>',6),
('00000000-0000-0000-0000-000000000003','Integrated / Short-term / Momentary LUFS','<p>Три окна измерения LUFS: Integrated — среднее по всему треку (именно по нему нормализуют стриминги), Short-term — по последним 3 секундам, Momentary — по последним 0.4 секунды.</p>',7),
('00000000-0000-0000-0000-000000000003','PLR (Peak to Loudness Ratio)','<p>Разница между пиковым уровнем и интегрированной громкостью трека — по сути показывает, сколько динамики «принесено в жертву» ради громкости.</p>',8),
('00000000-0000-0000-0000-000000000003','Клиппинг','<p>Обрезание сигнала при превышении цифрового потолка 0 dBFS — превращает пики в плоские «срезанные» участки и добавляет искажения.</p>',9),

-- Пространство и стерео
('00000000-0000-0000-0000-000000000004','Панорама (Pan)','<p>Положение звука между левым и правым каналом стерео-поля.</p>',1),
('00000000-0000-0000-0000-000000000004','Pan Law','<p>Правило, по которому меняется громкость звука при панорамировании к центру или краям, чтобы моно-сумма звучала ровно по громкости.</p>',2),
('00000000-0000-0000-0000-000000000004','Эффект Хааса (Haas Effect)','<p>Если один и тот же сигнал приходит в оба уха с задержкой 1–30 мс, мозг слышит один источник, но «шире». Основа многих техник расширения стерео.</p>',3),
('00000000-0000-0000-0000-000000000004','Реверберация','<p>Множество отражений звука от поверхностей помещения, создающие ощущение пространства и объёма.</p>',4),
('00000000-0000-0000-0000-000000000004','Задержка (Delay)','<p>Повтор сигнала через заданное время. В отличие от реверберации, повторы отчётливые и раздельные, а не размытые.</p>',5),
('00000000-0000-0000-0000-000000000004','Моно-совместимость','<p>Звучит ли микс нормально, если свести стерео в один канал. Важно для клубных систем, ТВ и части стриминговых сценариев.</p>',6),
('00000000-0000-0000-0000-000000000004','Ширина стерео (Stereo Width)','<p>Насколько широко звук ощущается за пределами позиции колонок — регулируется панорамой, задержками и M/S-обработкой. Излишнее расширение вредит моно-совместимости.</p>',7),
('00000000-0000-0000-0000-000000000004','Фазовая корреляция','<p>Показатель (от -1 до +1) того, насколько левый и правый каналы «совпадают» по фазе. Около +1 — почти моно, около -1 — каналы противофазны и рискуют пропасть в моно.</p>',8),
('00000000-0000-0000-0000-000000000004','M/S-обработка','<p>Разложение стерео-сигнала на Mid (общая, моно-часть) и Side (разница между каналами) для раздельной обработки каждой составляющей.</p>',9),
('00000000-0000-0000-0000-000000000004','Импульсный отклик (IR)','<p>Запись того, как конкретное помещение или устройство отвечает на короткий щелчок — используется в конволюционной реверберации и кабинетах гитарных усилителей для точной имитации реального пространства.</p>',10),
('00000000-0000-0000-0000-000000000004','Бинауральное аудио','<p>Запись или синтез звука с расчётом на восприятие двумя ушами так, чтобы в наушниках создавалось объёмное 3D-ощущение положения источников.</p>',11),

-- Запись
('00000000-0000-0000-0000-000000000005','Фантомное питание (+48V)','<p>Напряжение, которое микшер или аудиоинтерфейс подаёт на конденсаторный микрофон через XLR-кабель.</p>',1),
('00000000-0000-0000-0000-000000000005','Proximity Effect','<p>Усиление низких частот, когда источник (обычно голос) подносят близко к направленному микрофону.</p>',2),
('00000000-0000-0000-0000-000000000005','DI-бокс','<p>Устройство, согласующее сигнал инструмента (гитара, бас) с линейным входом интерфейса напрямую, без микрофона.</p>',3),
('00000000-0000-0000-0000-000000000005','Гейн-стейджинг','<p>Выстраивание правильного уровня сигнала на каждом этапе цепи — запись, плагины, мастер-шина — чтобы избежать лишнего шума и клиппинга.</p>',4),
('00000000-0000-0000-0000-000000000005','Диаграмма направленности микрофона','<p>Кардиоида (слышит спереди), всенаправленная (слышит везде одинаково), восьмёрка (слышит спереди и сзади) — определяет, откуда микрофон в первую очередь берёт звук и сколько комнаты попадёт в запись.</p>',5),
('00000000-0000-0000-0000-000000000005','Овердаб','<p>Запись дополнительной партии поверх уже существующей — например, повторный дубль вокала или гармония, добавленная к основной дорожке.</p>',6),
('00000000-0000-0000-0000-000000000005','Комп (Comping)','<p>Сборка одного идеального дубля из кусочков нескольких записанных попыток одной и той же партии.</p>',7),
('00000000-0000-0000-0000-000000000005','Предусилитель (Preamp)','<p>Устройство, поднимающее слабый сигнал микрофона до рабочего уровня перед оцифровкой — сильно влияет на итоговый характер звука записи.</p>',8),
('00000000-0000-0000-0000-000000000005','Close-mic vs Room-mic','<p>Запись вплотную к источнику даёт сухой, детальный и контролируемый звук; запись комнатным микрофоном на расстоянии добавляет естественную акустику и объём помещения.</p>',9),

-- Сведение
('00000000-0000-0000-0000-000000000006','Балансировка уровней','<p>Первый и самый важный этап сведения — выставление относительной громкости всех дорожек друг к другу до применения любой обработки.</p>',1),
('00000000-0000-0000-0000-000000000006','Автоматизация','<p>Запрограммированное изменение параметра (громкости, панорамы, эффекта) во времени — например, плавное поднятие вокала в припеве.</p>',2),
('00000000-0000-0000-0000-000000000006','Групповая шина (Bus)','<p>Виртуальный канал, объединяющий несколько дорожек (например, все барабаны) для общей обработки и управления одним фейдером.</p>',3),
('00000000-0000-0000-0000-000000000006','Референс-трек','<p>Профессионально сведённый трек из того же жанра, с которым сравнивают свой микс по балансу, громкости и тональности в процессе работы.</p>',4),
('00000000-0000-0000-0000-000000000006','Маскирование частот','<p>Когда два инструмента конкурируют за один и тот же частотный диапазон и «заглушают» друг друга — решается панорамой, EQ-вырезами или подбором аранжировки.</p>',5),
('00000000-0000-0000-0000-000000000006','Send / Return (шина эффектов)','<p>Отправка части сигнала дорожки на общий эффект (например, реверберацию) с возвратом обработанного сигнала обратно в микс — экономит ресурсы и даёт единое пространство для всех инструментов.</p>',6),
('00000000-0000-0000-0000-000000000006','Печать эффектов (Print)','<p>Финальная фиксация обработки (записанная в аудио, а не оставленная в виде живого плагина) — иногда нужна для переноса проекта или экономии ресурсов процессора.</p>',7),
('00000000-0000-0000-0000-000000000006','Стволы (Stems)','<p>Промежуточные групповые миксы (вокал, барабаны, бас, музыка), выгруженные отдельно — используются для мастеринга или ремиксов без доступа к полному проекту.</p>',8),

-- Мастеринг
('00000000-0000-0000-0000-000000000007','Дизеринг (Dither)','<p>Добавление контролируемого шума при понижении битности (например, с 24 до 16 бит), чтобы избежать искажений квантования.</p>',1),
('00000000-0000-0000-0000-000000000007','Нормализация','<p>Приведение громкости трека к заданному уровню — пиковому или по LUFS.</p>',2),
('00000000-0000-0000-0000-000000000007','Каскад обработки (Chain)','<p>Порядок, в котором сигнал проходит через плагины: например EQ → компрессор → лимитер.</p>',3),
('00000000-0000-0000-0000-000000000007','Референс-мастеринг','<p>Сравнение своего мастера с треками-эталонами того же жанра по громкости, тональному балансу и плотности перед финальным утверждением.</p>',4),
('00000000-0000-0000-0000-000000000007','Аналоговая сумма','<p>Пропуск цифрового микса через аналоговое оборудование (пульт, ленточные машины, хардверные компрессоры) для добавления характерных тёплых нелинейных искажений.</p>',5),
('00000000-0000-0000-0000-000000000007','ISRC-код','<p>Уникальный международный идентификатор записи, который присваивается треку при мастеринге для дистрибуции и учёта роялти.</p>',6),

-- Модуляция и эффекты
('00000000-0000-0000-0000-000000000008','Хорус (Chorus)','<p>Эффект, имитирующий одновременное звучание нескольких похожих, но слегка расстроенных и смещённых во времени источников — делает звук «шире» и «богаче».</p>',1),
('00000000-0000-0000-0000-000000000008','Фленжер (Flanger)','<p>Смешивание сигнала с его копией с плавно меняющейся короткой задержкой — даёт характерный «реактивный», свистящий гребенчатый эффект.</p>',2),
('00000000-0000-0000-0000-000000000008','Фейзер (Phaser)','<p>Сдвиг фазы части сигнала с последующим смешиванием с оригиналом — создаёт плавающий, вращающийся тональный эффект без явного эффекта задержки.</p>',3),
('00000000-0000-0000-0000-000000000008','Тремоло','<p>Периодическое изменение громкости сигнала по заданной скорости — классический «пульсирующий» эффект.</p>',4),
('00000000-0000-0000-0000-000000000008','Вибрато','<p>Периодическое изменение высоты тона сигнала — в отличие от тремоло, «плавает» не громкость, а питч.</p>',5),
('00000000-0000-0000-0000-000000000008','LFO (низкочастотный генератор)','<p>Генератор медленных, обычно не слышимых напрямую колебаний, который используют для управления другими параметрами — например, скоростью тремоло или глубиной хоруса.</p>',6),
('00000000-0000-0000-0000-000000000008','Питч-шифтер','<p>Изменяет высоту тона сигнала вверх или вниз, обычно без изменения его длительности — основа для гармонайзеров и коррекции строя.</p>',7),
('00000000-0000-0000-0000-000000000008','Гармонайзер','<p>Добавляет к исходному сигналу одну или несколько нот с заданным интервалом, создавая многоголосную гармонию из одной дорожки.</p>',8),

-- Синтез и электронная музыка
('00000000-0000-0000-0000-000000000009','Осциллятор','<p>Базовый источник звука синтезатора, генерирующий периодический сигнал заданной формы (синус, пила, прямоугольник и т.д.), из которого строится дальнейший тембр.</p>',1),
('00000000-0000-0000-0000-000000000009','Огибающая (ADSR)','<p>Attack / Decay / Sustain / Release — то, как параметр (обычно громкость) звука меняется во времени от нажатия ноты до её затухания.</p>',2),
('00000000-0000-0000-0000-000000000009','Фильтр синтезатора','<p>Формирует тембр, вырезая или подчёркивая части спектра осциллятора (часто с резонансом на срезе) — самый узнаваемый инструмент синтеза наравне с осциллятором.</p>',3),
('00000000-0000-0000-0000-000000000009','Wavetable-синтез','<p>Синтез, при котором тембр формируется путём переключения и плавного перехода между набором заранее записанных форм волны — даёт более сложные, эволюционирующие тембры, чем простой аналоговый синтез.</p>',4),
('00000000-0000-0000-0000-000000000009','MIDI','<p>Цифровой протокол передачи музыкальных данных (какая нота, с какой силой и когда нажата) между инструментами, контроллерами и программами — сам по себе не содержит звука.</p>',5),
('00000000-0000-0000-0000-000000000009','Квантизация (в MIDI)','<p>Автоматическое подтягивание сыгранных нот к ближайшей ритмической сетке (например, к шестнадцатым) для идеально ровного по времени исполнения.</p>',6),
('00000000-0000-0000-0000-000000000009','Сайдчейн-компрессия в EDM','<p>Ритмичное «проседание» громкости баса или пэдов под удар кика на каждую долю — фирменный пульсирующий эффект многих электронных жанров, достигается сайдчейн-компрессором.</p>',7),

-- Форматы и технологии
('00000000-0000-0000-0000-000000000010','Частота дискретизации (Sample Rate)','<p>Сколько раз в секунду аналоговый сигнал измеряется при оцифровке (например, 44100 или 48000 Гц) — определяет верхнюю границу частот, которые можно записать.</p>',1),
('00000000-0000-0000-0000-000000000010','Битность (Bit Depth)','<p>Сколько бит используется для описания амплитуды каждого сэмпла (16, 24, 32 бита) — определяет динамический диапазон и уровень шума квантования записи.</p>',2),
('00000000-0000-0000-0000-000000000010','Латентность (Latency)','<p>Задержка между входным и выходным сигналом системы — критична при живой записи с мониторингом через компьютер, регулируется размером буфера.</p>',3),
('00000000-0000-0000-0000-000000000010','Размер буфера (Buffer Size)','<p>Сколько сэмплов аудиоинтерфейс обрабатывает за один блок — маленький буфер даёт низкую задержку, но нагружает процессор; большой — наоборот.</p>',4),
('00000000-0000-0000-0000-000000000010','Форматы плагинов (VST / AU / AAX)','<p>Разные технические стандарты, по которым плагины подключаются к разным digital audio workstation — VST повсеместен, AU нужен для Logic/GarageBand на macOS, AAX — для Pro Tools.</p>',5),
('00000000-0000-0000-0000-000000000010','Кодек с потерями / без потерь','<p>MP3/AAC необратимо выбрасывают часть данных ради малого размера файла (с потерями); WAV/FLAC/ALAC сохраняют весь сигнал точно (FLAC/ALAC ещё и сжимают его без потерь).</p>',6),
('00000000-0000-0000-0000-000000000010','ASIO','<p>Низкоуровневый протокол связи аудиоинтерфейса с компьютером на Windows, дающий минимальную задержку в обход стандартного звукового драйвера системы.</p>',7);
